public class EventBooking
{
  public int Id { get; set; }

  // 1. Add a method to search for the number of available seats in an event.
  private async Task<int> FindAvailableSeats(int id)
    => await _context
      .Tickets
      .Where(x=>x.EventId == id && x.Status==TicketState.Booked || Status==TicketState.Invalid)
      .CountAsync();

  public class Ticket
  {
    // 2. Add a method to purchase seats in an event. 
    private async Task PurchaseSeats(int ticketCount, int eventId) 
      => await _context
        .Tickets
        .Where(x=>x.EventId == id && x.Status==TicketState.Booked || Status==TicketState.Invalid);
    {
      if (ticketCount > await FindAvailableSeats(eventId)) return false;
      for (int i = 0; i < ticketCount; ++i)
        _context.Tickets
          .Add(new Ticket {EventId=eventId, Status=TicketState.Booked});
      var result = await _context.SaveChangesAsync(); 
      return result == ticketCount;
    }
  }
